import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface CurrentEpisode {
  title: string;
  podcastName: string;
  duration: string;
  currentProgress: string;
}

interface ListeningStats {
  totalHours: number;
  episodesCompleted: number;
  favoriteGenres: string[];
}

interface PodcastData {
  currentEpisode: CurrentEpisode;
  listeningStats: ListeningStats;
}

export default function Widget() {
  const { currentEpisode, listeningStats } = response.data as PodcastData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 300,
        maxWidth: 400,
        bgcolor: theme === 'dark' ? '#1F2937' : '#FFFFFF',
        color: theme === 'dark' ? '#F8FAFC' : '#1F2937',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Now Playing
            </Typography>
            <Typography variant="h6" sx={{ color: accentColor, fontWeight: 600 }}>
              {currentEpisode.title}
            </Typography>
            <Typography variant="body2" sx={{ color: primaryColor }}>
              {currentEpisode.podcastName}
            </Typography>
            <Typography variant="caption" sx={{ color: theme === 'dark' ? '#9CA3AF' : '#6B7280' }}>
              {currentEpisode.currentProgress} / {currentEpisode.duration}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Listening Stats
            </Typography>
            <Stack direction="row" spacing={3}>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Total Hours
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {listeningStats.totalHours}
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Episodes Completed
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {listeningStats.episodesCompleted}
                </Typography>
              </Box>
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Favorite Genres
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {listeningStats.favoriteGenres.map((genre, index) => (
                <Chip
                  key={index}
                  label={genre}
                  sx={{
                    fontSize: '11px',
                    bgcolor: theme === 'dark' ? '#374151' : '#E5E7EB',
                    color: theme === 'dark' ? '#F8FAFC' : '#1F2937',
                  }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
